using System.ComponentModel.DataAnnotations;

namespace sv_bcd8f0ae635a4304822b4f6ec1f81aff.Models;

public class RegistrationModel
{
    [Required(ErrorMessage = "Attendee name is required.")]
    [Display(Name = "Attendee Name")]
    public string AttendeeName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string Email { get; set; } = string.Empty;

    [Range(0, 5, ErrorMessage = "Number of guests must be between 0 and 5.")]
    [Display(Name = "Number of Guests")]
    public int NumberOfGuests { get; set; }

    [Required(ErrorMessage = "Please select a preferred session.")]
    [Display(Name = "Preferred Session")]
    public string PreferredSession { get; set; } = string.Empty;

    [Display(Name = "Special Dietary Requirements")]
    public string? DietaryRequirements { get; set; }
}

using sv_bcd8f0ae635a4304822b4f6ec1f81aff.Models;

namespace sv_bcd8f0ae635a4304822b4f6ec1f81aff.Services;

public class RegistrationService
{
    /// <summary>
    /// Validates the registration on the server side.
    /// Returns a dictionary of field-specific errors (field name → error message).
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAsync(RegistrationModel model)
    {
        var errors = new Dictionary<string, string>();

        // Simulate a duplicate-email check against a data store.
        if (model.Email.Equals("taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(model.Email)] = "This email is already registered.";
        }

        return Task.FromResult(errors);
    }
}

@page "/register"
@rendermode InteractiveServer
@using sv_bcd8f0ae635a4304822b4f6ec1f81aff.Models
@using sv_bcd8f0ae635a4304822b4f6ec1f81aff.Services
@inject RegistrationService RegistrationService

<PageTitle>Event Registration</PageTitle>

<h3>Event Registration</h3>

@if (isSubmitted)
{
    <div class="alert alert-success mt-3">
        <strong>Registration successful!</strong> Thank you, @model.AttendeeName.
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="register" class="mt-3" style="max-width: 500px;">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="attendeeName" class="form-label">Attendee Name</label>
            <InputText id="attendeeName" class="form-control" @bind-Value="model.AttendeeName" />
            <ValidationMessage For="() => model.AttendeeName" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label for="numberOfGuests" class="form-label">Number of Guests</label>
            <InputNumber id="numberOfGuests" class="form-control" @bind-Value="model.NumberOfGuests" />
            <ValidationMessage For="() => model.NumberOfGuests" />
        </div>

        <div class="mb-3">
            <label for="preferredSession" class="form-label">Preferred Session</label>
            <InputSelect id="preferredSession" class="form-select" @bind-Value="model.PreferredSession">
                <option value="">-- Select a session --</option>
                <option value="Morning">Morning</option>
                <option value="Afternoon">Afternoon</option>
                <option value="Evening">Evening</option>
            </InputSelect>
            <ValidationMessage For="() => model.PreferredSession" />
        </div>

        <div class="mb-3">
            <label for="dietaryRequirements" class="form-label">Special Dietary Requirements</label>
            <InputTextArea id="dietaryRequirements" class="form-control" @bind-Value="model.DietaryRequirements" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isProcessing">
            @if (isProcessing)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            }
            Register
        </button>
    </EditForm>
}

@code {
    private RegistrationModel model = new();
    private EditContext? editContext;
    private ValidationMessageStore? messageStore;
    private bool isSubmitted;
    private bool isProcessing;

    protected override void OnInitialized()
    {
        editContext = new EditContext(model);
        messageStore = new ValidationMessageStore(editContext);

        // Clear server-side errors whenever a field changes so the user can retry.
        editContext.OnFieldChanged += (_, args) =>
        {
            messageStore.Clear(args.FieldIdentifier);
            editContext.NotifyValidationStateChanged();
        };
    }

    private async Task HandleSubmit()
    {
        isProcessing = true;

        try
        {
            var serverErrors = await RegistrationService.ValidateAsync(model);

            if (serverErrors.Count > 0)
            {
                foreach (var (field, error) in serverErrors)
                {
                    messageStore!.Add(editContext!.Field(field), error);
                }
                editContext!.NotifyValidationStateChanged();
                return;
            }

            isSubmitted = true;
        }
        finally
        {
            isProcessing = false;
        }
    }
}

